INSERT INTO `products` VALUES (10,'Антиринум (Кученце)','Подходящо за:\r\n\r\nВисоки цветни бордюри и лехи: Създава прекрасен заден план на по-ниски цветя или плътни цветни петна в градината.\r\nРязан цвят: Високите и прави дръжки правят този сорт отличен за букети. Цветовете се запазват свежи във ваза за дълго време, внасяйки аромат и уют в дома\r\n\r\nТехнология на отглеждане:\r\n\r\nСеитба: Засейте семената за разсад на закрито през февруари – март. Тъй като са много дребни, не ги покривайте с пръст, а само ги притиснете към влажния субстрат.\r\nЗасаждане: Изнасяне на открито през май, след като опасността от слани премине.\r\nРазстояние: Оставяйте по 20 – 30 см между растенията.\r\nПрофесионален съвет (Пензиране): За да получите по-разклонен и кичест храст, откъснете (пензирайте) върха на основното стъбло, когато растението достигне височина 10 см.\r\nГрижи: Поливайте редовно, без да заблатявате. Почистването на прецъфтелите цветове стимулира появата на нови пъпки.',0.90,200,'https://sortovisemena-bg.com/uploadedimages/2026/1/18/a8ac950ad9126c5eae364acae322bf6eBig.jpg',1,NULL),(11,'Газания (Летен гербер )','Тези чудесни едногодишни цветя са подходящи както за градини и паркове, така и за дворни и вилни места. Познато у нас като \"Летен гербер\".  Тази красавица ще ви зарадва с безкраен цъфтеж от юни до настъпването на първите слани. За да се постигнете този цъфтеж е нужно да се засадят на слънчево място. Растенията са устойчиви на топлина и суша. \r\n\r\nЗасаждане и грижи\r\nСемената се засяват от януари до април в лека почва. \r\nРазсаждането се извършва от края на април до началото на май на разстояние от 25 до 30 см.',0.90,250,'https://sortovisemena-bg.com/uploadedimages/2023/12/13/19cd40af1c7ae1859676b4de14157c07Big.jpg',1,NULL),(12,'Декоративна трева (Синя трева)','Описание на семена Декоративна трева Blue grass ( Festuca glauca)\r\nВид: Декоративна трева\r\nСорт: Blue grass (Синя трева)\r\nЦвят: Синьо-сребрист\r\nВисочина: 15-20 см\r\nПериод на цъфтеж: Юни-юли\r\n\r\nОтглеждане:\r\nЗасяване: април-май или септември-октомври\r\nСеитба: директно в градината\r\nДълбочина на засяване: 0,5-1 см\r\nРазстояние между растенията: 10-15 см\r\nПредпочитана почва: добре дренирана, плодородна\r\nСветлина: слънчево място или полусянка\r\nВреме за покълване: 10-14 дни\r\nТемпература за покълване: 15-20°C',1.00,300,'https://sortovisemena-bg.com/uploadedimages/2024/2/15/b8878255cc85fbffe68d8c387a842439Big.jpg',1,NULL),(13,'Дигиталис (Напръстник)','Цветето Дигиталис известно още като Напръстник е много привлекателно и красиво. Цветовете се намират на къса дръжка и са събрани в горната част на стъблото, което достига височина до 1,3 метра. Пoдхoдящo за цветни градини, паркове и бoрдюри.\r\n\r\nДвугодишно\r\nСeитбa: мaй – юни   \r\nРaзсaждaнe: сeптeмври \r\nЦъфтeж:  – aвгуст \r\nРaзстoяниe: 30  40 см ',0.90,300,'https://sortovisemena-bg.com/uploadedimages/2023/12/14/beef958629d45b53ff22a06e046b90d4Big.jpg',1,NULL),(14,'Лаватера микс','Това растение е едгодишно, устойчиво и може да достигне височина от 80-90см. То продължително цъфти до късна есен. Това растение е изключително лесно за отглеждане и поддръжка. \r\nТо е подходящо за украса на разноцветни участъци в градини, паркове и балкони. \r\nСемената се сеят от февруари до май, за да цъфне от юли до октомври. Предпочита слънчеви места.',0.90,300,'https://sortovisemena-bg.com/uploadedimages/2023/12/25/8dd74ee6b9f878c6e594f7a3f6552110Big.jpg',1,NULL),(15,'Месембриантемум (Обедно цвете)','Цветето образува много на брой цветове с ярки цветови нюанси и продължителен период на цъфтеж. Външният вид на цветчетата му наподобява маргаритка или гербера. Месембриатемумът предпочита обилната слънчева светлина и не понася натрупване на влага.\r\n\r\nУказания за успешното отглеждане на това цвете:\r\nСеитба: Тази операция се извършва през март месец.\r\nРазсаждане: Препоръчително е да бъде разсадено през април месец.\r\nПериод на цъфтеж: От юли до октомври.\r\nРазстояние между цветовете: 10 х 20 см.',0.90,200,'https://sortovisemena-bg.com/uploadedimages/2023/12/14/9b782d67dfb27c3f12b033bdcc0de68bBig.jpg',1,NULL),(16,'Незабравка','Лесна за отглеждане: Процъфтява на различни видове почви и не се нуждае от често поливане.\r\nДълъг цъфтеж: Радва ви с цветове през пролетта и началото на лятото.\r\nИдеална за начинаещи градинари: Дори ако нямате опит, лесно ще отгледате незабравки.\r\nПодходяща за различни условия: Може да расте както на слънце, така и на полусянка.\r\nУказания за отглеждане:\r\nПоливане: Обича влажна почва, но не и прекалено напоена.\r\nСемената се засяват: октомври - ноември\r\nРазстояние: 20 х 30 см\r\nВисочина: 25 см\r\nЦъфтеж: април - юни',0.90,300,'https://sortovisemena-bg.com/uploadedimages/2025/1/13/a8e7f401690fa7479ce081c42c62e84dBig.jpg',1,NULL),(17,'Аквилегия (Кандилка)','Многогодишно градинско растение с височина 70 см.\r\nМоже да се отглежда на пряко слънце и полусенчести места, не се препоръчва отглеждане на пълна сянка.\r\nЦъфтеж - м. май - м. юни.\r\n\r\nИнструкции за засаждане и грижи:\r\nСемената се засяват на закрито - февруари - март и цъфтят още първата година. \r\nСемената се засяват на открито  през месец март или април. \r\nДълбочина 0,3 см, като трябва добре да ги притиснете, за да имат контакт с почвената влага.\r\nПоливайте редовно при изсъхване на почвата.',0.90,300,'https://sortovisemena-bg.com/uploadedimages/2023/12/14/628ba180c4291567ba74395702a3a16bBig.jpg',1,NULL),(18,'Карамфил шабо микс','Многогодишно декоративно растение устойчиво на суша и ниски температури.\r\nОбразува 60 см туфи отрупани с единични едри кичести цветове с големина 7 см. \r\nОтглеждат се предимно за рязан цвят. Предпочита слънчеви места и добре запасени почви. \r\nРедовно поливане и подхранване. При фаза ботунация и началото на цъфтежа задължително трябва да се подхранят с калиев тор. След няколко години растенията се израждат и трябва да бъдат подновени. \r\nЦъфтеж: Юли-Октомври',0.90,300,'https://sortovisemena-bg.com/uploadedimages/2021/4/10/4be1ef648cb29f9772134ae0660f93c0Big.jpg',1,NULL),(19,'Петуния Балконна','Едногодишно растение с разклоняващи се стъбла с височина до 30 см  с овални , слабо удължени листа.\r\nВирее добре на слънце, на леки, оцедливи и добре запасени с хранителни вещвства почви. Използва се за цветни лехи и бордюри в паркове и градини, отглежда се и на балкони.\r\nСемената се засяват през февруари - март',0.90,200,'https://sortovisemena-bg.com/uploadedimages/2011/9/06/84ad25d149ea7dd24de0516dad767d62Big.jpg',1,NULL),(20,'Ралица микс','Едногодишно светлолюбиво растения с прави изправени стъбла. Цветовете са едри кичести със събрани в дълги гроздовидни съцветия. Много лесно се отглежда. Обича слънчеви места и умерено поливане и подхранване с минерални торове. \r\nСемената се засяват февруари - март, за да се произведе разсад или направо в градината през април - май. Цъфти от юли до късна есен.\r\n',0.90,250,'https://sortovisemena-bg.com/uploadedimages/2010/7/06/30f85c7f8c72b0ee1ecad0c2584528c2Big.jpg',1,NULL),(21,'Лупина','Многогодишно растение, достигащо височина до 120 см, подходящо за полусенчести места.\r\n\r\nСеитба за разсад: септември-октомври\r\nСеитба на открито: април-май\r\nЦъфтеж: юни-септември (на следващата година)',0.90,250,'https://sortovisemena-bg.com/uploadedimages/2016/11/23/45653dbc7fcf369c7138f9bf2f4a47cdBig.jpg',1,NULL),(22,'Бегония Рекс (Царска Бегония)','Царската бегония е една от най-красивите бегонии. Нейното обаяние идва заради декоративно оцветените ѝ листа. Те са обагрени в разнообразни цветове – зелено, бяло, розово, бронзово-кафяво, сребристо, червено-виолетово, на петна, с металически блясък или с кадифени и розови пръски. Листата на царската бегония са неравномерни по форма. Едни са издължени, други овални, трети с назъбени ръбове. Тя все пак цъфти, но цветовете ѝ далеч не са така впечатляващи като листата, защото са малки и невзрачни. През лятото, когато слънчевата светлина е силна, царската бегония се поставя на полусенчесто място, защитено от пряка светлина. Тя изгаря красивите листа на растението. През зимата саксията се премества на добре осветено място с пряка светлина, тъй като тогава слънцето е много по-слабо. През лятото поливането на царската бегония е обилно и ежедневно. За целта почвата трябва да е с осигурен добър дренаж. През зимата поливането значително се разрежда. Пръстта трябва да се оставя да изсъхне напълно между две поливания. Царската бегония обича високата влажност. Препоръчително е саксията да се оставя върху съд, пълен с вода, която да се изпарява.',6.50,300,'https://danielbg.com/wp-content/uploads/2024/06/image-771655.jpg',2,NULL),(23,'Еониум','Това храстоподобно растение с типични за сукулентите месести листа се числи към семейство Дебелецови (Crassulaceae). Еониум произлиза от Мароко, но е разпространено и в другите средиземноморски райони с мека зима, където се отглежда на открито. Разположете го на отлично проветрено място с минимална температура от 10 градуса. В зоните с мек климат, еониумът може да бъде държан на открито през цялата година. За избуяването му са нужни поне 13 градуса, но и над 21 градуса не му се отразяват зле. За да се развиват най-добре и да запазят необичайната си окраска, всички разновидности на еониума се нуждаят от силно осветление. През лятото го напоявайте обилно, като оставяте почвата да изсъхне между отделните поливания. През зимата поддържайте ниска почвена влага. Поливайте само, когато листата започна да завяхват. Подобно на почти всички сукуленти, няма нужда от висока въздушна влага.',5.00,250,'https://danielbg.com/wp-content/uploads/2025/09/image-011-2.jpg',2,NULL),(24,'Каладиум','Каладиумът предпочита светли места, но защитени от пряка слънчева светлина. Прекалено силната светлина може да изгори листата, докато липсата на светлина води до избледняване на ярките цветове. Изисква постоянно влажна, но не преовлажнена почва. Поливането трябва да се регулира според температурата и влажността на околната среда, като се увеличава честотата през лятото и се намалява през зимата. Избягвайте излагане на студени въздушни течения или температури под 15 градуса по Целзий. Торете растението веднъж месечно през активния период на растеж (пролет-лято) с водоразтворим, балансиран тор. Изберете почва, богата на органична материя, с добра дренажна способност.',18.00,200,'https://danielbg.com/wp-content/uploads/2025/08/20250830_104611.jpg',2,NULL),(25,'Адениум (Пустинна роза)','Адениумът се нуждае от високи температури. Нужни са 20-25 °C освен обилната светлина. Понася добре жегите. Добре е през лятото саксията да се изнася навън. Слънчевата тераса ще хареса на розата от пустинята. С поливането трябва много да се внимава. Това растение има способността да складира водата, затова едно поливане седмично е достатъчно. Между поливанията субстратът трябва да подсъхне.  Необходими са 6-8 часа слънчево греене за нормално развитие и обилен цъфтеж. Южният прозорец е добра опция на пустинната роза.',10.70,300,'https://danielbg.com/wp-content/uploads/2025/09/image-091.jpg',2,NULL),(26,'Антуриум Лили','Отглеждането на антуриум у дома има своите тънкости, но не е особено трудно. Растението ще се чувства най-добре на топло, защитено от течение място, по възможност при висока въздушна влажност. Ако въздухът в помещението е сух, можете да подредите камъчета в подложката и да я напълните с вода, така че тя да се изпарява, без да има досег с почвата в саксията. Опръскването с вода се отразява много добре, но при студено време е за предпочитане да се избягва, защото може да доведе до гъбни заболявания. Антуриумите обичат обилната светлина, но прякото слънце е много вредно за тях. Както повечето растения, които обитават тропическите гори, те издържат на сянка. Обикновено обаче реагират на недостатъчната осветеност, като спират да цъфтят. Оптималната температура е между 20 и 28 градуса, а резките промени на топлината са нежелателни. През зимата не бива да остават на по-хладно от 17-18 градуса. Поливането трябва да бъде редовно, но внимателно – антуриумът понася по-добре лекото засушаване отколкото излишъка на вода.',11.50,250,'https://danielbg.com/wp-content/uploads/2024/08/image-825861.jpg',2,NULL),(27,'Билбергия','Билбергията расте на места от светли до полусенчести, възможно е слънчево място, но защитено от преките слънчеви лъчи в обедните часове. Растението понася добре свежия въздух. През зимата дръжте при стайна температура с малки колебания. Постоянното пребиваване при температура, по-ниска от 10 градуса, може да предизвика усложнения. Почвата в саксията трябва да бъде постоянно влажна, въпреки че за кратко време може да понесе и суха почва. През зимата при прохладно помещение поливайте ограничено.',6.00,200,'https://danielbg.com/wp-content/uploads/2024/07/image-780456.jpg',2,NULL),(28,'Каланхое Розова Пеперуда','Каланхое „Розови пеперуди“ е атрактивно сукулентно растение, известно с ярките си цветове и уникалната характеристика да образува множество малки растителни листа, наподобяващи розови пеперуди. Грижата за каланхое е минимална, но бъдете внимателни с нивата на светлина. Интензивната слънчева светлина може да изгори върховете на листата. Когато отглеждате каланхое, поставете саксиите на места с частично слънце или лека сянка.',3.00,350,'https://danielbg.com/wp-content/uploads/2025/05/image-1053819.jpg',2,NULL),(29,'Куфея','Куфеята предпочита слънчеви или леко сенчести места и добре дренирана почва. Тя е сравнително сухоустойчива, но редовното поливане през вегетационния период ще спомогне за по-обилен цъфтеж. За да стимулирате повторен цъфтеж, е препоръчително да премахвате прецъфтелите цветове. За съжаление, куфеята е много чувствителна към студ и не понася температури под 0°C. В по-студените райони се отглежда като едногодишно растение. За да удължите периода на цъфтеж, можете да я приберете на защитено място през зимата или да я отглеждате в саксия, която да внесете на закрито при първите есенни слани.',6.20,300,'https://danielbg.com/wp-content/uploads/2025/09/image-053.jpg',2,NULL),(30,'Спатифилум','Спатифилумът се чувства отлично в топли помещения. Най-удачната температура за него е между 16 и 21 градуса. За да се постигнат добри резултати при отглеждането на му е нуобходимо да се осигури ярка светлина и умерена влажност. Както много други стайни цветя и спатифилумът може да вирее на по-затъмнено и пи по-ниски температури, но тогава расте бавно и ще цъфти рядко. Затова през зимата е необходимо цветето да се сложи близо до прозорец. Прeз пролетта и лятото трябва да се осигури висока влажност.',5.30,250,'https://danielbg.com/wp-content/uploads/2024/11/image-94344.jpg',2,NULL),(31,'Хлорофитум','Едно от най-непретенциозните растения отглеждани в дома. Безгрижният хлорофитум  е много популярен и широко разпространен, защото лесно развива бързо вкореняващи се млади растения. Оптималната температура за отглеждане на хлорофитум е умерена, като през зимата не следва да е по-ниска от 18 градуса. Студените течения при отглеждане в близост до прозорци с прорези могат да нанесат вреди на растението. Растението предпочита ярка, но заедно с това разсеяна светлина. Стайните растения хлорофитум се чувстват прекрасно на източни или на западни прозорци. През лятото холорофитум се нуждае от напръскване и с удоволствие приема топъл душ. През зимата напръскване е необходимо само в случаите, когато растението е поставено в близост до отоплителната система.',5.00,300,'https://danielbg.com/wp-content/uploads/2023/07/image-131726.png',2,NULL),(32,'Фитония','Фитонията предпочита ярка, но разсеяна светлина. Избягвайте директната слънчева светлина, тъй като тя може да изсуши листата и да доведе до изгаряния. Идеална е за интериори с умерено осветление. Растението обича влажна почва, но не търпи задържана вода. Поливайте редовно, като се уверите, че водата може да оттича добре от саксията. През зимата намалете поливането, но не допускайте почвата да изсъхне напълно. Фитонията обича висока влажност, така че при сух въздух (особено през зимата) може да се наложи да я пръскате с вода или да използвате овлажнител. Това растение е чувствително към студени температури, така че поддържайте температурата в помещението между 18°C и 24°C. Не обича резки температурни колебания.\r\n',5.80,400,'https://danielbg.com/wp-content/uploads/2025/09/image-016-1.jpg   ',2,NULL),(33,'Сансевиера','Сансевиерата е красиво декоративно растение с ефектни листа, изпъстрени в тъмно и светло зелени нюанси. На височина достига до около 60 см. Стайното растение е известно още под името Индийски меч, Рицарски меч, както и закачливото наименование Свекървин език. Цветето Сансевиера обича светлината, затова трябва да е разположено на добре осветено място. Светлината прави шарките на листата по-пъстри и наситени. Все пак трябва да се избягва и прякото силно слънчево огряване, тъй като това може да доведе до изгаряния по листата. Сенчестите позиции също не са за препоръчване, защото сансевиерата трудно понася сянката. Сансевиерата се чувства най-добре на по-топло, въпреки че може да понесе и по-хладна температура, но не по-ниска от 10 градуса, тъй като може да се окаже пагубна за него. Затова през зимата е хубаво да се държи в затоплено помещение, за да се избегне риска от измръзване. През летните месеци, когато температурите достигат 25-30 градуса, сансевиерата нараства бързо и ако се отглежда на подходящо светло място, дава и цветове в бяло-зелен нюанс. Цветчетата са дребнички и излъчват нежен деликатен аромат. Разположени са върху дълго цветоносно стъбло, събрани в грозд. За сансевиерата е характерно, че е доста издръжливо растение, тъй като съхранява водни запаси в листата си. Ето защо не трябва да се прекалява с поливането. Най-добре е да се изчака почвата да изсъхне добре преди следващо напояване. При поливане листата трябва да се пазят от намокряне, тъй като в случай на останала върху листата или в тяхната основа вода, това може да причини загниване.',12.30,354,'https://danielbg.com/wp-content/uploads/2024/06/image-763554.jpg',2,NULL),(34,'Витекс (Арабски люляк)','За предпочитане е да е на слънчево и добре дренирано място, защитено от студени ветрове. Понася и известна полусянка. Може да се оформя като ниско дръвче или разклонен храст, в зависимост от вашите предпочитания. Успешно може да се отглежда в цялата страна, без райони с подчертано студена зима.Отглежда се с декоративна и лечебна цел. Всички части на растението са използваеми. Цветовете са медоносни и се развиват от ранна пролет до късна есен, след което образува плодчета. Листата са ароматни и дори в изсушен вид могат да се използват за борба срещу комари и молци. В медицината намира приложение при главоболие, акне, ревматизъм и др. В много източни страни можете да срещнете Витекса под различни наименования като Свещения храст, Дървото Цар и др. и навсякъде народните му имена са следствие на лечебните му качества. В превод от гръцки името му означава ‘целомъдрие’.',16.40,250,'https://danielbg.com/wp-content/uploads/2024/06/image-762554.jpg',3,NULL),(35,'Гаура','Гаура е тревисто растение с ефектни розови цветове и много продължителен период на цъфтеж – практически през цялото лято и началото на есента. Слабо популярно, но много ефектно и напълно зимоустойчиво за България растение.  Образува гъста туфа с остри обагрени в червено листа, между които на тънки стебла се появяват множество розови цветчета, подобни на пеперуди. Обича добре дренирана, богатa почва и е много издръжлива на засушаване. Издържа без каквито и да е проблеми и най-големите летни горещини. Презимува успешно у нас при температури до -22°C, но за да нямате проблеми му осигурете добре дренирана почва . В по-топли климатични пояси листата му остават вечнозелени през цялата година. У нас те опадват изцяло при температури под нулата през зимата, но рано напролет веднага избиват отново от коренището.',6.20,150,'https://danielbg.com/wp-content/uploads/2024/05/image-658538.png',3,NULL),(36,'Жасмин Вариегатен','Почвата, подходяща за жасмина, е добре дренирана, а мястото, което да изберете, е добре да бъде на пълно слънце, върху здрава опора като пергола. Някои видове ще се справят добре и на сянка, но заложете на сигурното и ги засадете на слънчево място. Подхранвайте ежеседмично с тор с високо съдържание на калий през лятото и мулчирайте през есента с добре угнил оборски тор или листна плесен. След цъфтеж е нужно да подрязвате цветето.',16.70,190,'https://danielbg.com/wp-content/uploads/2024/09/image-863865.jpg',3,NULL),(37,'Олеандър (Зокум)','Зокумът е вечнозелено растение с дълги и тесни кожести листа и изящни едри цветове. Цъфтежът започва в средата на лятото и при благоприятни условия продължава до октомври. Всички части на олеандъра са отровни, поради което деца и домашни любимци не бива да имат достъп до него. При работа с растението трябва да се използват ръкавици, след което ръцете да се измиват старателно. Сладникавия и интензивен аромат на повечето сортове може да предизвика главоболие у някои по-чувствителни хора, така че не е добра идея да го отглеждате в спалнята. Обича топлината, чувства се отлично на стайна температура между 23 и 28 градуса. Понася без проблем летните горещини, но при екстремно високи температури малко забавя темпа си на растеж. През зимата може да се държи в хладно помещение, но температурата не бива да пада под 5 градуса. Не обича резките температурни промени. Прекомерното поливане може да унищожи растението затова бъдете внимателни. През топлия сезон се полива когато горния слой на почвата започне да изсъхва. Използвайте топла, престояла вода. През зимата се полива рядко – веднъж на 10 дни. В горещото време е добре да пръскате листата на растението с топла, мека вода. През зимата го дръжте далеч от отоплителните уреди и ако въздухът е сух, отново пулверизирайте.',13.00,260,'https://danielbg.com/wp-content/uploads/2025/06/image-1097623.jpg',3,NULL),(38,'Плумбаго','Плумбаго е светлолюбиво растение, затова се нуждае от доста слънце. Дръжте го на топло и светло място, като температурата лятото не трябва да надвишава 25-27 градуса. Зимата пак трябва да е на светло и по-добре да е на закрито, защото не издържа на температури под 4 градуса. Плумбагото изисква редовно поливане – внимавайте почвата да не изсъхва, защото тогава цветето няма да цъфти. Важно е също периодично да пулверизирате. Когато цветчетата прецъфтят, трябва да се махнат, за да направите място за нови. Най-късно през септември е време да приберете растението на закрито.',12.60,236,'https://danielbg.com/wp-content/uploads/2025/07/image-1103524.jpg',3,NULL),(39,'Хипериум','Нискорастящ вечнозелен полухраст, характерен с големите си жълти цветове през цялото лято. Има почвопокривни свойства, тъй като много лесно се разпространява на свободни пространства. Цъфти c пpeĸpacни, яpĸo жълти цвeтoвe oт юни дo ceптeмвpи-октомври. Xипepиĸyмът е много устоичив и невзискателен към условия вид. Рacтe и ce paзвивa дoбpe ĸaĸтo нa cянĸa, тaĸa и нa cлънцe, на всякакъв вид почва стига само да не е изцяло прогизнала от влага, добре се развива и на засушени почви. Добре е хиперикума да се подрязва подчти до дъно рано на пролет през март месец, така се поддържа оптималното му развитие, сгъстява се по бързо и се стимулира по обилния му цъфтеж. Тъй като е много агресивен вид може да се ограничава неговото разпространяване чрез подрязване.',9.00,266,'https://danielbg.com/wp-content/uploads/2024/06/image-753252.jpg',3,NULL),(40,'Аблоция','Юлибрисиновата албиция е известна също и като „копринено дърво“. Растението се нарича често и „спящо дърво“, тъй като привечер листата му се затварят в спящо положение. Албицията е топлолюбиво растение и обича защитени от студен вятър места. Вирее на пропускливи, глинести почви и на топло, слънчево изложение. У нас може да расте само в Южна България и покрай Черноморието. Отделни растения могат да бъдат видяни в по-северни области, но там те страдат от по-ниските температури, тъй като албицията издържа до около -16 градуса. Отглежда се лесно и може да я видите в почти всеки двор на крайморските къщи, където внася много екзотика, характерна за топлите райони в близост до морето. Цени се много заради красивата форма на короната си, светлата си листна маса и уникалните си тичинки.',30.00,189,'https://danielbg.com/wp-content/uploads/2023/08/image-237043.jpg',3,NULL),(41,'Ринкоспермум (Лъжлив жасмин)','Наричан още „лъжлив жасмин” и „звездовиден жасмин”, растението е вечнозелена лиана, достигаща до 3 м дължина. Ринкоспермум  е увивен храст с много ароматни цветове. Изисква пълно слънце или най-много шарена сянка. При отглеждане в стаи или оранжерии с южно изложение може да се наложи засенчване. Това се прави, за да се предпазят листата от изгаряне. Расте много добре в плодородни и дренирани почви. Може да се отглежда и в контейнери. Цъфтежът на „Звездовидния Жасмин“ е през ранна пролет до август. Цветовете са умерено количество, звездовидни, не много големи, обагрени в искрящо бяло. Ароматът им е силен и отчетлив. Подходящ за използване като декоративна, покривна растителност и за жив плет.',14.90,398,'https://danielbg.com/wp-content/uploads/2025/04/image-1030317.jpg',3,NULL),(42,'Ескалония','Ескалонията е вечнозелен храст с атрактивни, лъскави зелени листа и тръбести цветове, които са малки, но толкова многобройни, че превръщат растението във всеобщ любимец. Образува жив плет в много крайбрежни области. Расте на всякаква градинска почва, но предпочита песъчливи, богати, добре дренирани почви, на слънце или полусянка. На север засадете до стена. Есента намалете дължината на прецъфтелите клонки и подрежете живия плет. Няма нищо против вятъра, така че може да бъде добра бариера за други по-деликатни растения.',16.40,295,'https://danielbg.com/wp-content/uploads/2024/06/image-766854.jpg',3,NULL),(43,'Калистемон цитринус','На размер при отглеждане в саксия достига до около 1 м. височина и също толкова на ширина. Обикновено растежът му е храстовиден, но компактен, може да бъде оформен и като малко дръвче.  Калистемон цитринус е вечнозелен.Съцветията са 6 до 10 см. дълги и 4 до 7 см. в диаметър. Съставени са от множество дълги, пурпурно червени тичинки и са подобни на четка за почистване на бутилки. Именно този външен вид на цветовете го прави един от най-очарователните храсти, които можете да отглеждате в саксия. Няма друго растение, което да изглежда толкова впечатляващо и същевременно да изисква толкова малко грижи.Най-обилният цъфтеж е често на два пъти – през пролетта и отново през есента, но често Калистемонът цъфти спорадично и през цялата година.Освен това Калисемон цинтринус започва да цъфти от много малък и като размер и като възраст.\r\nКалистемон цитринус не понася температури по-ниски от няколко градуса под нулата, затова презимуването трябва да става на закрито в светло и хладно помещение.',18.00,378,'https://danielbg.com/wp-content/uploads/2019/03/image-108421.png',3,NULL),(44,'Маслина','Маслината е субтропично вечнозелено растение, дърветата са изключително дълголетни. У нас тази култура се отглежда предимно с декоративна цел в контейнери, като през зимния период трябва да се защити от студа. Маслината е един от най-студоустойчивите субтропични овощни видове. Все пак предпочита горещо лято и мека зима, т.е. много слънце. Издръжливостта на ниски температури зависи от сорта и възрастта на дървото. Варира от минус 12 до минус 18 градуса. Силните ветрове през зимата могат да причинят повреди по листата, пъпките и по-тънките клони. Най-чувствителни на ниски температури са цветовете на маслината – издържат до минус 2 градуса, а зрелите плодове до – минус 3. Маслината има отлична сухоустойчивост. За да се справи с горещия и сух климат, маслиновото дърво има малки листа със защитно покритие. Естествено, когато целта е да се получи качествена реколта, необходимо е дръвчетата да се поливат. Маслината изисква много светлина, за да расте и да се развива правилно. Растението не понася засенчване.',40.00,361,'https://danielbg.com/wp-content/uploads/2025/05/image-1048219.jpg',3,NULL),(45,'Рафиолепис','Расте изключително бавно, обича слънчеви места, но понася и значителна сянка. Предпочита влажни, добре дренирани, леко кисели почви. През лятото поливането е редовно, но умерено, през зимата е ограничено. Ако отглеждате тези растения в саксии, трябва да ги поливате малко по-често от растенията, отглеждани в земята. Не изисква пръскане. През зимата температурата не трябва да пада под 5-7°C и не надвишава 15-17°C. Възрастните растения могат да понасят студове до -15°C. На всеки 2-3 години растенията се презасаждат или почвата се обогатява с органични торове.',23.00,345,'https://danielbg.com/wp-content/uploads/2025/05/image-1042719.jpg',3,NULL),(47,'Букет Грация','Създаден с внимание към детайла, букетът “Грация” съчетава нежността на белите рози, изящната хортензия, ефирната еустома и деликатните бели спрей рози. Всяко цвете допълва другото, създавайки усещане за чистота, стил и класа.\r\nИдеален избор за специални поводи или като изискан жест на внимание и обич.\r\nВидове цветя: Еустоми, Рози, Хортензии\r\n\r\n ',40.00,279,'https://gebov.bg/wp-content/uploads/2025/02/335b-scaled.jpg',5,NULL),(48,'Букет Романтика ','Впечатляващ и стилен, този букет от 51 бели и розови рози съчетава елегантност и нежност в съвършена хармония. Всяка роза е подбрана с внимание, за да създаде изискано цветно послание. Опакован в стилна бяла хартия, този букет е символ на чистота, изтънченост и романтика.\r\nПерфектният избор за всеки специален момент, когато искате да оставите незабравимо впечатление.',100.00,358,'https://gebov.bg/wp-content/uploads/2025/02/339-scaled.jpg',5,NULL),(49,'Букет Скарлет','Съчетание от изящни червени рози, червени спрей рози и хиперикум, този букет излъчва страст и елегантност. Опакован в стилна бяла хартия, той създава впечатляващ контраст и подчертава красотата на всеки детайл.\r\nНаправете жест, който няма да остане незабелязан, и зарадвайте любим човек с този изискан букет.',80.00,234,'https://gebov.bg/wp-content/uploads/2025/02/334b-scaled.jpg',5,NULL),(50,'Букет Малена','Изключително стилен и нежен букет с микс от рози и евкалипт.',50.00,365,'https://gebov.bg/wp-content/uploads/2020/11/239-scaled.jpg',5,NULL),(51,'Букет от 51 лалета','Ярък и жизнерадостен, този букет от 51 разноцветни лалета носи свежестта и красотата на пролетта. Съчетанието от нежни пастелни и наситени тонове създава усещане за енергия, радост и ново начало.\r\nИдеален подарък, който ще озари всеки повод с цветно настроение и стил.',60.00,249,'https://gebov.bg/wp-content/uploads/2022/02/200b-scaled.webp',5,NULL),(52,'Букет Рита','Прекрасен цветен букет с микс от рози, еустоми, хортензии, алстромерии и евкалипт.',50.00,361,'https://gebov.bg/wp-content/uploads/2023/01/MG_6618-scaled.jpg',5,NULL),(53,'Букет от 51 цветни рози','Неповторим букет от 51 уникални разноцветни рози, изработен с много любов! Защото най-специалните хора го заслужават!',120.00,362,'https://gebov.bg/wp-content/uploads/2022/02/199b-scaled.jpg',5,NULL),(54,'Букет от 101 червени рози','Възхитителен букет от 101 уникални червени рози, изработен с много любов! Защото най-специалните хора го заслужават!',200.00,298,'https://gebov.bg/wp-content/uploads/2022/02/198a.jpg',5,NULL),(55,'Букет от гипсофил разноцветен','Ефирен, лек и запомнящ се – този голям букет от разноцветен гипсофил съчетава нежност и въздушност в един изключително впечатляващ аранжимент. Фините му цветове преливат в пастелни нюанси, създавайки усещане за лекота и романтика.\r\nПерфектен избор за всеки, който цени красотата в детайлите и иска да подари нещо наистина специално.',100.00,310,'https://gebov.bg/wp-content/uploads/2022/02/341a-1152x1536.webp',5,NULL),(56,'Букет с 5 бели орхидеи','Букет с пет бели орхидеи,евкалипт и сепла опаковка.',40.00,459,'https://buketite.net/wp-content/uploads/2023/01/1631023286_73cf2c8e-8698-46ab-bde0-fce47595621d.jpeg',5,NULL),(57,'Букет с ириси','Керамична ваза с ириси и алстромерия – за пролетно настроение и уют.',48.00,393,'https://www.feya.bg/wp-content/uploads/2026/02/sdsd.png',5,NULL),(59,'Букет Валъри','Цветен, игрив букет с много настроение.\r\nЦветя:\r\nРози\r\nРози спрей\r\nОрхидея цимбидиум\r\nАлстромерия\r\nОпаковка: Матиран целофан\r\nДекорация: Панделка сатен, Пера\r\nМоже би бихте хареса',47.00,211,'https://www.feya.bg/wp-content/uploads/2025/06/%D0%91%D1%83%D0%BA%D0%B5%D1%82-%D0%92%D0%B0%D0%BB%D1%8A%D1%80%D0%B8.jpg',5,NULL);
